form:Form.form:Scripts:
		function PosOnLoad()
{
	if (Ctrl('main').GetMode()=='NEW')
  {
  	Ctrl('oi_empresa').SetXValue('');
  	Ctrl('oi_terminal').SetXValue('');
  	Ctrl('horainicio').SetXValue('');
  	Ctrl('horafin').SetXValue('');

  	var nSQL = GetProxy().SQLService();
	  var xmlParam = new NomadXML('DATA');	  
		var objResult = nSQL.GetOBJ(Ctrl("main").getResource("QRY_MIN_TERMINAL"), xmlParam.ToString());		
		Ctrl('oi_terminal').SetXValue(objResult.oi_terminal);
  }

	if (Ctrl('main').GetMode()=='SHOW' || Ctrl('main').GetMode()=='EDIT')
  {
    //Conversion de cantidad de minutos al formato HHMMSS
    var minutos = Number(Ctrl('e_horainicio').GetXValue());
    var MM = minutos % 60;
    var HH = (minutos - MM)/60;
    if (HH >= 24) HH = HH - 24;
    Ctrl('horainicio').SetXValue(pad2(HH)+pad2(MM)+'00');

		//Conversion de cantidad de minutos al formato HHMMSS    
    minutos = Number(Ctrl('e_horafin').GetXValue());
    MM = minutos % 60;
    HH = (minutos - MM)/60;
    if (HH >= 24) HH = HH - 24;
    Ctrl('horafin').SetXValue(pad2(HH)+pad2(MM)+'00');

    //Obtener Empresa
    var nSQL = GetProxy().SQLService();
	  var xmlParam = new NomadXML('PARAM');
	  xmlParam.SetAttr('oi_personal_emp', Ctrl('oi_personal_emp').GetXValue());	  
		var objResult = nSQL.GetOBJ(Ctrl("main").getResource('QRY_EMPRESA'), xmlParam.ToString());		
		Ctrl('oi_empresa').SetXValue(objResult.oi_empresa);
  }	
}

function pad2(number)
{
   return (number < 10 ? '0' : '') + number;
}

function terminal_onchange()
{
	if (Ctrl('main').GetMode()=='NEW' && Ctrl('oi_terminal').GetXValue() != '')
	{
	  var nSQL = GetProxy().SQLService();
	  var xmlParam = new NomadXML('DATA');
	  xmlParam.SetAttr('oi_terminal', Ctrl('oi_terminal').GetXValue());
		var objResult = nSQL.GetOBJ(Ctrl("main").getResource("QRY_ESTRUCTURA"), xmlParam.ToString());		
		Ctrl('oi_estructura').SetXValue(objResult.oi_estructura);
	}
}

qry:select.qry:xquery:
for $r in SQL('
SELECT TTA05_TERMINALES.oi_estructura FROM TTA05_TERMINALES WHERE TTA05_TERMINALES.oi_terminal = {$PARAM/@oi_terminal}
')/ROWS/ROW

for $r in SQL('
SELECT PER02_PERSONAL_EMP.oi_empresa FROM PER02_PERSONAL_EMP WHERE PER02_PERSONAL_EMP.oi_personal_emp = {$PARAM/@oi_personal_emp}
')/ROWS/ROW
